&lt;p&gt;&amp;nbsp;&lt;/p&gt;<br><br>&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;अवधारणा&lt;/span&gt;&lt;/u&gt;&amp;nbsp;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ध्वनि:&lt;/span&gt;&amp;nbsp;ध्वनि एक स्थानीय विक्षोभ से ज्यादा कुछ नहीं है जिसका प्रसार कणों के बीच टकरावों द्वारा किया जाता है;&amp;nbsp;यह विक्षोभ&amp;nbsp;एक अनुदैर्ध्य तरंग में फैलती है; जैसे कि एक कण दुसरे कण से टकराता है और फिर कण अगले कण के टकराता है इसी प्रकार आगे भी होता है|

	&lt;ul&gt;
		&lt;li&gt;यह एक यांत्रिक तरंग है जिसे यात्रा करने के लिए एक माध्यम की आवश्यकता होती है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ध्वनि&lt;/span&gt;&amp;nbsp;की&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;गति तरल की तुलना में ठोस में अधिकतम है और गैसों में&lt;/span&gt;&amp;nbsp;सबसे धीमी है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ध्वनि की गति:&lt;/span&gt;&amp;nbsp;ध्वनि तरंगों द्वारा प्रति इकाई समय में तय की गई दूरी जैसे यह एक प्रत्यास्थ माध्यम से प्रसार करती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;गैसीय माध्यम में ध्वनि का वेग निम्न द्वारा दिया जाता है:&lt;/p&gt;

&lt;p&gt;&lt;span class=&quot;math-tex&quot;&gt;\(\Rightarrow v=\sqrt {\frac {γ P}{ρ}}\)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;जहां P = दबाव, &amp;rho; = घनत्व, और &amp;gamma; = गैस के दो प्रमुख विशिष्ट ऊष्माओं का&amp;nbsp;अनुपात&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;ध्वनि की गति समान भौतिक स्थितियों के तहत किसी दिए गए माध्यम में सभी आवृत्तियों के लिए लगभग समान रहती है।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;पदार्थ की&lt;/span&gt;&amp;nbsp;एक&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;अवस्था&lt;/span&gt;&amp;nbsp;अलग-अलग रूपों में से एक है, जिसमें पदार्थ मौजूद हो सकता है।
	&lt;ul&gt;
		&lt;li&gt;पदार्थ&amp;nbsp;की चार मूलभूत अवस्थाएँ हैं -&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;ठोस, तरल पदार्थ, गैसें और प्लाज्मा&lt;/span&gt;।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;व्याख्या&lt;/span&gt;&lt;/u&gt;:&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ठोस-अवस्था&lt;/span&gt;&amp;nbsp;पदार्थ की&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;चार&lt;/span&gt;&amp;nbsp;मूलभूत अवस्थाओं में से एक है, जिसमें घटक कण (आयन, परमाणु आदि) एक साथ&amp;nbsp;पैक किए जाते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;ध्वनि&lt;/span&gt;&amp;nbsp;की&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;गति ठोस में सबसे अधिक है&lt;/span&gt;&amp;nbsp;और गैसों में कम से कम। अत:&amp;nbsp;विकल्प 2 सही है।&lt;/li&gt;
&lt;/ul&gt;

